class ApiDirectory:
    # Directorio Maestro: Se actualiza aquí, se propaga en todas las llamadas.
    ENDPOINTS = {
        'KALSHI': 'https://external-api.kalshi.com/trade-api/v2',
        'SUPABASE': 'https://nvfufmgkbgcigbftzbne.supabase.co',
        'GROQ': 'https://api.groq.com/openai/v1',
        'RENDER': 'https://api.render.com/v1'
    }

    @classmethod
    def update_or_add(cls, service, url):
        cls.ENDPOINTS[service.upper()] = url

import os, requests
from dotenv import load_dotenv
from api_directory import ApiDirectory

load_dotenv()

class AetraClient:
    def __init__(self):
        self.dir = ApiDirectory()

    def request(self, service, path, method='GET', payload=None):
        url = f'{self.dir.get_url(service)}{path}'
        key = os.getenv(f'{service.upper()}_API_KEY')
        if not key: raise Exception(f'Credencial {service}_API_KEY no encontrada en .env')
        headers = {'Authorization': f'Bearer {key}', 'Content-Type': 'application/json'}
        return requests.request(method, url, json=payload, headers=headers)
